class Solution {
public:
    int maxSatisfied(vector<int>& customers, vector<int>& grumpy, int minutes) {
        int n = customers.size();
        int total = 0;
        for (int i = 0; i < n; i++) {
            if (grumpy[i] == 0) {
                total += customers[i];
            }
        }
        int max_extra = 0;
        int window_extra = 0;
        for (int i = 0; i < n; i++) {
            window_extra += grumpy[i] * customers[i];
            if (i >= minutes) {
                window_extra -= grumpy[i - minutes] * customers[i - minutes];
            }
            max_extra = max(max_extra, window_extra);
        }
        return total + max_extra;
    }
};
```
